export { default as SNavigationMenu } from './navigation-menu.vue';

export type * from '@soybeanjs/headless/navigation-menu';
export type * from './types';

import type {
  NavigationMenuCompactProps,
  NavigationMenuCompactEmits,
  NavigationMenuCompactSlots,
  NavigationMenuUi
} from '@soybeanjs/headless/navigation-menu';
import type { ClassValue } from '@soybeanjs/headless/types';
import type { ThemeSize } from '@/theme';

/**
 * Properties for the NavigationMenu component.
 */
export interface NavigationMenuProps extends NavigationMenuCompactProps {
  /**
   * Additional class names applied to the root element.
   */
  class?: ClassValue;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: Partial<NavigationMenuUi>;
}

/**
 * Events for the NavigationMenu component.
 */
export type NavigationMenuEmits = NavigationMenuCompactEmits;

/**
 * Slots for the NavigationMenu component.
 */
export type NavigationMenuSlots = NavigationMenuCompactSlots;

import type { ThemeSize } from './types';

export const themeSizeMap: Record<ThemeSize, number> = {
  xs: 12,
  sm: 14,
  md: 16,
  lg: 18,
  xl: 20,
  '2xl': 24
};
export const miniSizeMap: Record<ThemeSize, ThemeSize> = {
  xs: 'xs',
  sm: 'xs',
  md: 'sm',
  lg: 'md',
  xl: 'lg',
  '2xl': 'xl'
};

export const themeSizeRatio = Object.fromEntries(
  Object.entries(themeSizeMap).map(([key, value]) => [key, value / themeSizeMap.md])
) as Record<ThemeSize, number>;
